def process(list, fieldName):
    """Sum a specific field across all structs in a list"""
    if not list or not isinstance(list, (list, tuple)):
        return 0.0
    field = str(fieldName or '')
    total = 0.0
    for item in list:
        if isinstance(item, dict) and field in item:
            try:
                total += float(item[field])
            except (TypeError, ValueError):
                pass
    return total
